#include<bits/stdc++.h>
using namespace std;
constexpr int mod1=39989,mod2=1e9;
constexpr double eps=1e-9;
typedef pair<double,int> pdi;
int cmp(double x,double y)
{
    if(x-y>eps)
    {
        return 1;
    }
    if(y-x>eps)
    {
        return -1;
    }
    return 0;
}
struct line
{
    double k,b;
}p[200010];
int s[200010],cnt;
double calc(int id,int x)
{
    return p[id].k*x+p[id].b;
}
void add(int ax,int ay,int bx,int by)
{
    cnt++;
    if(ax==bx)
    {
        p[cnt].k=0;
        p[cnt].b=max(ay,by);
    }
    else
    {
        p[cnt].k=1.0*(by-ay)/(bx-ax);
        p[cnt].b=ay-p[cnt].k*ax;
    }
}
void update1(int x,int l,int r,int u)
{
    int &v=s[x],mid=(l+r)>>1;
    int bmid=cmp(calc(u,mid),calc(v,mid));
    if(bmid==1||(bmid==0&&u<v))
    {
        swap(u,v);
    }
    int bl=cmp(calc(u,l),calc(v,l)),br=cmp(calc(u,r),calc(v,r));
    if(bl==1||(bl==0&&u<v))
    {
        update1(x<<1,l,mid,u);
    }
    if(br==1||(br==0&&u<v))
    {
        update1(x<<1|1,mid+1,r,u);
    }
}
void update(int x,int l,int r,int u,int v,int p)
{
    if(u<=l&&r<=v)
    {
        update1(x,l,r,p);
        return;
    }
    int mid=(l+r)>>1;
    if(u<=mid)
    {
        update(x<<1,l,mid,u,v,p);
    }
    if(v>mid)
    {
        update(x<<1|1,mid+1,r,u,v,p);
    }
}
pdi pmax(pdi x,pdi y)
{
    if(cmp(x.first,y.first)==-1)
    {
        return y;
    }
    else if(cmp(x.first,y.first)==1)
    {
        return x;
    }
    else if(x.second<y.second)
    {
        return x;
    }
    else
    {
        return y;
    }
}
pdi query(int x,int l,int r,int d)
{
    if(r<d||d<l)
    {
        return {0.0,0};
    }
    int mid=(l+r)>>1;
    double tmp=calc(s[x],d);
    if(l==r)
    {
        return {tmp,s[x]};
    }
    else
    {
        return pmax({tmp,s[x]},pmax(query(x<<1,l,mid,d),query(x<<1|1,mid+1,r,d)));
    }
}
int main()
{
    int n,lstans=0;
    scanf("%d",&n);
    while(n--)
    {
        int op;
        scanf("%d",&op);
        if(op==1)
        {
            int ax,ay,bx,by;
            scanf("%d%d%d%d",&ax,&ay,&bx,&by);
            ax=(ax+lstans-1+mod1)%mod1+1;
            bx=(bx+lstans-1+mod1)%mod1+1;
            ay=(ay+lstans-1+mod2)%mod2+1;
            by=(by+lstans-1+mod2)%mod2+1;
            if(ax>bx)
            {
                swap(ax,bx);
                swap(ay,by);
            }
            add(ax,ay,bx,by);
            update(1,1,mod1,ax,bx,cnt);
        }
        else
        {
            int x;
            scanf("%d",&x);
            x=(x+lstans-1+mod1)%mod1+1;
            printf("%d\n",lstans=query(1,1,mod1,x).second);
        }
    }
    return 0;
}
